//! Tier-C interpreter-embed correctness — the gg-walker-wasm packaging lane
//! (`aot_gg_embed.rs`), sibling of the Tier-A harness in
//! `wasm_correctness.rs`.
//!
//! Three layers, each honest about its gate:
//! - structural + fail-closed emitter checks — always run;
//! - checked-in walker fixture drift — always runs (regenerate with
//!   `cargo test --test gg_embed_correctness regen_walker_fixtures -- --ignored`);
//! - wasm parity vs gnexec under Node — runs when BOTH the prebuilt walker
//!   (`gg-walker-wasm/target/wasm32-unknown-unknown/release/gg_walker_wasm.wasm`,
//!   build: `cd gg-walker-wasm && cargo build --target wasm32-unknown-unknown
//!   --release`) AND `node` are available; skips politely otherwise.

use std::fs;
use std::path::{Path, PathBuf};
use std::process::Command;

use gnosis_polyglot::aot_gg_embed::{
    emit_gg_embed_for_export, gg_embed_topology_hash, prepare_gg_embed_artifacts,
    supports_gg_embed_for_export, walker_wasm_path,
};
use gnosis_polyglot::aot_wasm::BETTI_WASM_MANIFEST_SECTION;
use gnosis_polyglot::parse_and_extract_orchestration;
use gnosis_polyglot::serialization::PolyglotOrchestrationResult;
use serde_json::{json, Value};

/// json-v1 host sequence over the ENVELOPE input (the Tier-C contract:
/// `{"topology": …, "input": …}` rides in the input bytes). Envelope comes
/// from a file to keep argv small. Trap → exit 3, mirroring
/// wasm_correctness.rs.
const HARNESS_JS: &str = r#"
const fs = require('fs');
const [,, wasmPath, envelopePath] = process.argv;
const bytes = fs.readFileSync(wasmPath);
const mod = new WebAssembly.Module(bytes);
if (WebAssembly.Module.imports(mod).length !== 0) {
  console.error('emitted module must have an empty import section');
  process.exit(4);
}
const inst = new WebAssembly.Instance(mod, {});
const ex = inst.exports;
try {
  const input = fs.readFileSync(envelopePath);
  const p = ex.gnosis_alloc(input.length);
  new Uint8Array(ex.memory.buffer, p, input.length).set(input);
  const o = ex.main(p, input.length);
  const n = ex.gnosis_result_len();
  const text = new TextDecoder('utf-8', { fatal: true })
    .decode(new Uint8Array(ex.memory.buffer, o, n));
  JSON.parse(text); // json-v1 output must be valid JSON
  ex.gnosis_free(p, input.length);
  process.stdout.write(text);
} catch (e) {
  if (e instanceof WebAssembly.RuntimeError) process.exit(3);
  throw e;
}
"#;

fn benchmarks_dir() -> PathBuf {
    Path::new(env!("CARGO_MANIFEST_DIR")).join("../gnode/benchmarks")
}

fn fixtures_dir() -> PathBuf {
    Path::new(env!("CARGO_MANIFEST_DIR")).join("gg-walker-wasm/tests/fixtures")
}

/// Scan a benchmark fixture with its BASENAME as file_path so checked-in
/// topology fixtures stay machine-independent.
fn scan_benchmark(name: &str) -> (PolyglotOrchestrationResult, String) {
    let path = benchmarks_dir().join(name);
    let source = fs::read_to_string(&path)
        .unwrap_or_else(|e| panic!("read {}: {e}", path.display()));
    let scan = parse_and_extract_orchestration(&source, name)
        .unwrap_or_else(|e| panic!("scan {name}: {e}"));
    (scan, source)
}

fn node_available() -> bool {
    Command::new("node")
        .arg("--version")
        .output()
        .map(|out| out.status.success())
        .unwrap_or(false)
}

fn walker_available() -> bool {
    walker_wasm_path().exists()
}

/// Reference run: the real gnexec walker over the original `.gg` fixture.
fn gnexec_stdout(fixture: &str, export: &str, input_json: &str) -> String {
    let out = Command::new(env!("CARGO_BIN_EXE_gnexec"))
        .arg(benchmarks_dir().join(fixture))
        .args(["--export", export, "--input-json", input_json])
        .output()
        .expect("gnexec runs");
    assert!(
        out.status.success(),
        "gnexec {fixture} --export {export} failed:\n{}",
        String::from_utf8_lossy(&out.stderr)
    );
    String::from_utf8_lossy(&out.stdout).trim().to_string()
}

/// gnexec prints a bare string for `Value::String` results and JSON
/// otherwise; normalize the walker's JSON output the same way.
fn walker_json_as_gnexec_stdout(json_text: &str) -> String {
    match serde_json::from_str::<Value>(json_text).expect("walker output is valid JSON") {
        Value::String(s) => s,
        other => other.to_string(),
    }
}

struct NodeHarness {
    dir: tempfile::TempDir,
}

impl NodeHarness {
    fn new() -> Self {
        let dir = tempfile::tempdir().expect("tempdir");
        fs::write(dir.path().join("harness.js"), HARNESS_JS).expect("write harness");
        NodeHarness { dir }
    }

    /// Returns (stdout on success, exit code).
    fn run(&self, wasm_path: &Path, envelope: &Value) -> (Option<String>, Option<i32>) {
        let envelope_path = self.dir.path().join("envelope.json");
        fs::write(&envelope_path, serde_json::to_vec(envelope).unwrap()).expect("write envelope");
        let output = Command::new("node")
            .arg(self.dir.path().join("harness.js"))
            .arg(wasm_path)
            .arg(&envelope_path)
            .output()
            .expect("node harness runs");
        if !output.status.success() && output.status.code() != Some(3) {
            panic!(
                "harness failed unexpectedly (code {:?}):\n{}",
                output.status.code(),
                String::from_utf8_lossy(&output.stderr)
            );
        }
        let stdout = if output.status.success() {
            Some(String::from_utf8_lossy(&output.stdout).trim().to_string())
        } else {
            None
        };
        (stdout, output.status.code())
    }
}

/// Envelope construction — the documented host rule: a sidecar that is
/// exactly the `{"topology", "helpers"}` wrapper splices `input` into a v2
/// envelope; anything else is a bare v1 topology.
fn envelope_for(sidecar: &Value, input: &Value) -> Value {
    let is_wrapper = sidecar.as_object().is_some_and(|obj| {
        obj.len() == 2 && obj.contains_key("topology") && obj.contains_key("helpers")
    });
    if is_wrapper {
        json!({
            "topology": sidecar["topology"],
            "helpers": sidecar["helpers"],
            "input": input,
        })
    } else {
        json!({ "topology": sidecar, "input": input })
    }
}

// ── Checked-in walker fixture discipline ─────────────────────────────

fn fixture_pairs() -> [(&'static str, &'static str, &'static str); 4] {
    [
        ("fanout.gg", "app", "fanout.gg.topology.json"),
        ("echo.gg", "echo", "echo.gg.topology.json"),
        // Source-borne Tier C: echo.ts's export plus the helper its call
        // graph reaches (property-carried template/call/member IR).
        ("echo.ts", "app", "echo.ts.app.topology.json"),
        ("echo.ts", "greet", "echo.ts.greet.topology.json"),
    ]
}

/// gg-walker-wasm cannot depend on gnosis-polyglot, so its test fixtures are
/// CHECKED-IN copies of the extracted topologies. This test pins them to the
/// live extractor; on drift, re-run the ignored `regen_walker_fixtures`.
#[test]
fn checked_in_fixture_topologies_match_extractor() {
    for (fixture, export, fixture_file) in fixture_pairs() {
        let (scan, _) = scan_benchmark(fixture);
        let entry = scan
            .scan_result
            .topologies
            .iter()
            .find(|t| t.function_name == export)
            .unwrap_or_else(|| panic!("{fixture} has export {export}"));
        let live = serde_json::to_value(&entry.topology).expect("topology serializes");
        let path = fixtures_dir().join(fixture_file);
        let checked_in: Value = serde_json::from_str(
            &fs::read_to_string(&path).unwrap_or_else(|e| panic!("read {}: {e}", path.display())),
        )
        .expect("fixture parses");
        assert_eq!(
            live, checked_in,
            "extractor output drifted from {fixture_file}; regenerate with\n  \
             cargo test --test gg_embed_correctness regen_walker_fixtures -- --ignored"
        );
    }
}

/// Regenerates the checked-in walker fixtures from the live extractor.
/// Ignored by default: run explicitly after INTENTIONAL extractor changes,
/// then re-run the walker crate's tests to re-verify parity.
#[test]
#[ignore = "writes gg-walker-wasm/tests/fixtures; run after intentional extractor changes"]
fn regen_walker_fixtures() {
    for (fixture, export, fixture_file) in fixture_pairs() {
        let (scan, _) = scan_benchmark(fixture);
        let entry = scan
            .scan_result
            .topologies
            .iter()
            .find(|t| t.function_name == export)
            .unwrap_or_else(|| panic!("{fixture} has export {export}"));
        let json = serde_json::to_string_pretty(&entry.topology).expect("topology serializes");
        let path = fixtures_dir().join(fixture_file);
        fs::write(&path, format!("{json}\n"))
            .unwrap_or_else(|e| panic!("write {}: {e}", path.display()));
        println!("regenerated {}", path.display());
    }
}

// ── Emitter admission (always run; no walker binary needed to DECLINE) ──

#[test]
fn gg_embed_declines_outside_the_property_carried_subset() {
    // fib.ts's helper body is loops + `binary` arithmetic, and app's return
    // is a `call` in expression position (`String(value)`) — all outside the
    // property-carried subset. Tier C must refuse it (arithmetic/loops are
    // Tier A's compiled lane, not this walker's).
    let (scan, source) = scan_benchmark("fib.ts");
    assert!(
        !supports_gg_embed_for_export(&scan, "app"),
        "fib.ts app must be outside the walker subset"
    );
    let err = emit_gg_embed_for_export(&scan, &source, "app")
        .expect_err("emit must fail closed")
        .to_string();
    assert!(
        err.contains("property-carried subset"),
        "decline should say why: {err}"
    );

    // Unknown export fails closed too.
    assert!(!supports_gg_embed_for_export(&scan, "nope"));
    assert!(emit_gg_embed_for_export(&scan, &source, "nope").is_err());
}

/// Tier C breadth (source-borne echo.ts): the export calls a user-defined
/// helper (`greet`) whose semantics ride entirely in extractor-emitted IR
/// properties (template/call/member + `param_names`). The packager collects
/// the helper topology transitively, the sidecar becomes the
/// `{"topology","helpers"}` wrapper, and the walker's static admission
/// accepts the full program.
#[test]
fn gg_embed_supports_source_borne_echo_ts() {
    let (scan, source) = scan_benchmark("echo.ts");
    assert!(
        supports_gg_embed_for_export(&scan, "app"),
        "echo.ts app must be inside the walker subset (helpers carried)"
    );
    if !walker_available() {
        eprintln!("skipping emit half: prebuilt walker missing");
        return;
    }
    let emitted = emit_gg_embed_for_export(&scan, &source, "app").expect("echo.ts packages");
    let sidecar: Value = serde_json::from_str(&emitted.topology_json).expect("sidecar parses");
    let obj = sidecar.as_object().expect("sidecar is an object");
    assert_eq!(
        obj.len(),
        2,
        "sidecar is exactly the topology+helpers wrapper"
    );
    assert!(obj.contains_key("topology") && obj.contains_key("helpers"));
    assert!(
        sidecar["helpers"].get("greet").is_some(),
        "greet helper topology rides in the sidecar"
    );
    assert_eq!(
        emitted.manifest.topology_hash,
        gg_embed_topology_hash(&emitted.topology_json)
    );
    gg_walker_wasm::validate_program_json(&emitted.topology_json)
        .expect("sidecar program admits");
}

#[test]
fn gg_embed_supports_the_gg_fixtures() {
    let (fanout, _) = scan_benchmark("fanout.gg");
    assert!(supports_gg_embed_for_export(&fanout, "app"));
    let (echo, _) = scan_benchmark("echo.gg");
    assert!(supports_gg_embed_for_export(&echo, "echo"));
}

#[test]
fn gg_embed_requires_prebuilt_walker() {
    if walker_available() {
        eprintln!("skipping: walker binary present; missing-walker error path not exercisable");
        return;
    }
    let (scan, source) = scan_benchmark("fanout.gg");
    let err = emit_gg_embed_for_export(&scan, &source, "app")
        .expect_err("emit must fail closed without the walker binary")
        .to_string();
    assert!(err.contains("build gg-walker-wasm first"), "{err}");
}

// ── Structural checks on the emitted artifact (need the walker binary) ──

#[test]
fn gg_embed_emits_fanout_with_interpreter_embed_manifest() {
    if !walker_available() {
        eprintln!(
            "skipping: prebuilt walker missing at {} — \
             cd gg-walker-wasm && cargo build --target wasm32-unknown-unknown --release",
            walker_wasm_path().display()
        );
        return;
    }
    let (scan, source) = scan_benchmark("fanout.gg");
    let emitted = emit_gg_embed_for_export(&scan, &source, "app").expect("fanout.gg packages");

    let m = &emitted.manifest;
    assert_eq!(m.tier, "interpreter-embed");
    assert_eq!(m.certified_class, "gg-embed");
    assert_eq!(m.abi, "json-v1");
    assert_eq!(m.export_name, "main");
    assert_eq!(m.decline_semantics, "trap");
    assert!(m.imports.is_empty());
    assert_eq!(m.language, "gg");
    assert_eq!(m.function_name, "app");
    assert_eq!(m.topology_hash, gg_embed_topology_hash(&emitted.topology_json));
    assert_eq!(m.artifact_id.len(), 16);
    assert_eq!(m.sha256.len(), 64);
    // Integrity fields cover the CORE walker bytes (module minus the
    // trailing manifest custom section).
    assert!((m.byte_length as usize) < emitted.bytes.len());

    wasmparser::validate(&emitted.bytes).expect("emitted module validates");
    let mut found = false;
    for payload in wasmparser::Parser::new(0).parse_all(&emitted.bytes) {
        if let wasmparser::Payload::CustomSection(reader) = payload.expect("parse") {
            if reader.name() == BETTI_WASM_MANIFEST_SECTION {
                let embedded: Value =
                    serde_json::from_slice(reader.data()).expect("embedded manifest is JSON");
                assert_eq!(embedded["tier"], "interpreter-embed");
                assert_eq!(embedded["certified_class"], "gg-embed");
                found = true;
            }
        }
    }
    assert!(found, "gnosis-betti-manifest custom section present");

    // The pinned topology round-trips through the walker's own mirror.
    gg_walker_wasm::validate_topology_json(&emitted.topology_json)
        .expect("sidecar topology admits");
}

// ── Parity vs gnexec under Node (walker + node gated) ────────────────

#[test]
fn gg_embed_parity_vs_gnexec() {
    if !walker_available() {
        eprintln!("skipping: prebuilt walker missing (see module docs for the build one-liner)");
        return;
    }
    if !node_available() {
        eprintln!("skipping: node unavailable");
        return;
    }
    let harness = NodeHarness::new();
    let out_dir = tempfile::tempdir().expect("artifact dir");

    let cases: [(&str, &str, Value); 6] = [
        ("fanout.gg", "app", json!({"userId": "ada"})),
        ("fanout.gg", "app", json!({"userId": "grace-1"})),
        ("echo.gg", "echo", json!({"name": "ada"})),
        ("echo.gg", "echo", json!({})),
        // Source-borne Tier C: helper call + template IR (v2 envelope).
        ("echo.ts", "app", json!({"name": "x"})),
        ("echo.ts", "app", json!({"name": "ada"})),
    ];
    for (fixture, export, input) in cases {
        let (scan, source) = scan_benchmark(fixture);
        let artifacts =
            prepare_gg_embed_artifacts(&scan, &source, export, out_dir.path()).expect("packages");
        let sidecar: Value = serde_json::from_str(
            &fs::read_to_string(&artifacts.topology_path).expect("sidecar exists"),
        )
        .expect("sidecar parses");
        let envelope = envelope_for(&sidecar, &input);

        let (stdout, code) = harness.run(&artifacts.wasm_path, &envelope);
        assert_eq!(code, Some(0), "{fixture} should answer for {input}");
        let wasm_answer = walker_json_as_gnexec_stdout(&stdout.expect("answered"));

        let reference = gnexec_stdout(fixture, export, &input.to_string());
        assert_eq!(
            wasm_answer, reference,
            "walker-wasm and gnexec disagree on {fixture} input {input}"
        );
    }
}

#[test]
fn gg_embed_wasm_traps_fail_closed() {
    if !walker_available() || !node_available() {
        eprintln!("skipping: prebuilt walker or node unavailable");
        return;
    }
    let harness = NodeHarness::new();
    let (scan, source) = scan_benchmark("fanout.gg");
    let emitted = emit_gg_embed_for_export(&scan, &source, "app").expect("packages");
    let wasm_path = harness.dir.path().join("walker.wasm");
    fs::write(&wasm_path, &emitted.bytes).expect("write module");

    let topology: Value = serde_json::from_str(&emitted.topology_json).expect("topology parses");

    // Uncertified label on the walked path → trap (exit 3), no answer.
    let mut poisoned = topology.clone();
    poisoned["nodes"][0]["labels"] = json!(["MysteryNode"]);
    let (stdout, code) = harness.run(&wasm_path, &json!({"topology": poisoned, "input": {"userId": "ada"}}));
    assert_eq!(stdout, None, "poisoned topology must not answer");
    assert_eq!(code, Some(3), "decline is a trap");

    // Input-dependent decline: missing userId → trap at runtime.
    let (stdout, code) = harness.run(&wasm_path, &json!({"topology": topology, "input": {}}));
    assert_eq!(stdout, None, "missing userId must not answer");
    assert_eq!(code, Some(3), "decline is a trap");

    // Malformed envelope → trap.
    let (stdout, code) = harness.run(&wasm_path, &json!({"nope": true}));
    assert_eq!(stdout, None);
    assert_eq!(code, Some(3));

    // Tier C decline-not-divergence: echo.ts with a missing `name` field.
    // gnexec answers "hello:null" (JS stringification of undefined→null in
    // the template); the walker TRAPS instead of guessing at coercion.
    let (scan, source) = scan_benchmark("echo.ts");
    let emitted = emit_gg_embed_for_export(&scan, &source, "app").expect("echo.ts packages");
    let echo_wasm = harness.dir.path().join("walker-echo.wasm");
    fs::write(&echo_wasm, &emitted.bytes).expect("write module");
    let sidecar: Value = serde_json::from_str(&emitted.topology_json).expect("sidecar parses");
    let (stdout, code) = harness.run(&echo_wasm, &envelope_for(&sidecar, &json!({})));
    assert_eq!(stdout, None, "missing name must not answer");
    assert_eq!(code, Some(3), "decline is a trap");

    // Same program without its helper → trap (unknown callee at load).
    let mut orphaned = sidecar.clone();
    orphaned["helpers"] = json!({});
    let (stdout, code) = harness.run(&echo_wasm, &envelope_for(&orphaned, &json!({"name": "x"})));
    assert_eq!(stdout, None, "helper-less program must not answer");
    assert_eq!(code, Some(3), "decline is a trap");
}

// ── Cross-language property-carried IR (Wave A2) ─────────────────────
//
// The per-language echo fixtures mirror echo.ts semantics in each
// language's idiom (Python f-string + attr, Go fmt.Sprintf + map index,
// Ruby interpolation + hash index, Java `+` concat + Map.get). The
// extractors canonicalize those shapes into the SAME property-carried IR
// (template / member / call-with-bind / param_names), so one walker
// subset certifies all of them.

/// The A2 fixture matrix: (fixture, entry export).
fn echo_matrix() -> [(&'static str, &'static str); 5] {
    [
        ("echo.ts", "app"),
        ("echo.py", "app"),
        ("echo.go", "app"),
        ("echo.rb", "app"),
        ("echo.java", "app"),
    ]
}

/// Static admission for every language in the matrix — no walker binary
/// needed; `supports_gg_embed_for_export` runs the walker's own sweep
/// natively over root + collected helpers.
#[test]
fn gg_embed_supports_echo_class_across_languages() {
    for (fixture, export) in echo_matrix() {
        let (scan, _) = scan_benchmark(fixture);
        assert!(
            supports_gg_embed_for_export(&scan, export),
            "{fixture} export '{export}' must sit inside the walker's \
             property-carried subset"
        );
        assert!(
            supports_gg_embed_for_export(&scan, "greet"),
            "{fixture} helper 'greet' must certify standalone too"
        );
    }
}

/// Parity: for each language, the packaged Tier-C artifact answers the
/// SAME output as gnexec walking the original source natively.
#[test]
fn gg_embed_cross_language_parity_vs_gnexec() {
    if !walker_available() {
        eprintln!("skipping: prebuilt walker missing (see module docs for the build one-liner)");
        return;
    }
    if !node_available() {
        eprintln!("skipping: node unavailable");
        return;
    }
    let harness = NodeHarness::new();
    let out_dir = tempfile::tempdir().expect("artifact dir");

    for (fixture, export) in echo_matrix() {
        for input in [json!({"name": "x"}), json!({"name": "ada"})] {
            let (scan, source) = scan_benchmark(fixture);
            let artifacts = prepare_gg_embed_artifacts(&scan, &source, export, out_dir.path())
                .unwrap_or_else(|e| panic!("{fixture} packages: {e}"));
            let sidecar: Value = serde_json::from_str(
                &fs::read_to_string(&artifacts.topology_path).expect("sidecar exists"),
            )
            .expect("sidecar parses");
            let envelope = envelope_for(&sidecar, &input);

            let (stdout, code) = harness.run(&artifacts.wasm_path, &envelope);
            assert_eq!(code, Some(0), "{fixture} should answer for {input}");
            let wasm_answer = walker_json_as_gnexec_stdout(&stdout.expect("answered"));

            let reference = gnexec_stdout(fixture, export, &input.to_string());
            assert_eq!(
                wasm_answer, reference,
                "walker-wasm and gnexec disagree on {fixture} input {input}"
            );
        }
    }
}

/// Decline-not-divergence, per language: a missing `name` input field is
/// where language semantics genuinely differ (JS templates print `null`,
/// Python raises AttributeError, Ruby interpolates nil as "", Java
/// concatenates "null", Go prints zero values). The walker never guesses —
/// it traps for ALL of them.
#[test]
fn gg_embed_cross_language_missing_field_traps() {
    if !walker_available() || !node_available() {
        eprintln!("skipping: prebuilt walker or node unavailable");
        return;
    }
    let harness = NodeHarness::new();
    for (fixture, export) in echo_matrix() {
        let (scan, source) = scan_benchmark(fixture);
        let emitted =
            emit_gg_embed_for_export(&scan, &source, export).expect("echo-class packages");
        let wasm_path = harness
            .dir
            .path()
            .join(format!("walker-{}.wasm", fixture.replace('.', "-")));
        fs::write(&wasm_path, &emitted.bytes).expect("write module");
        let sidecar: Value =
            serde_json::from_str(&emitted.topology_json).expect("sidecar parses");
        let (stdout, code) = harness.run(&wasm_path, &envelope_for(&sidecar, &json!({})));
        assert_eq!(stdout, None, "{fixture}: missing name must not answer");
        assert_eq!(code, Some(3), "{fixture}: decline is a trap");
    }
}

/// Honest limits, pinned as declines (not silent divergence):
/// - `return greet(…)` — a helper call in RETURN position — is outside the
///   walker subset in EVERY language (calls are only certified as bound
///   statements). This was echo.py's original shape; it packages only
///   after the bind-then-return rewrite.
/// - Ruby implicit returns (no `return` keyword) carry no `expr` IR.
#[test]
fn gg_embed_declines_return_position_calls_and_implicit_returns() {
    let py = "def greet(name):\n    return f\"hello:{name}\"\n\n\ndef app(input):\n    return greet(input.name)\n";
    let scan = parse_and_extract_orchestration(py, "echo_return_call.py").expect("py scans");
    assert!(
        !supports_gg_embed_for_export(&scan, "app"),
        "return-position helper calls are outside the walker subset (python)"
    );

    let ts = "function greet(name: string): string {\n  return `hello:${name}`;\n}\n\nexport function app(input: { name: string }): string {\n  return greet(input.name);\n}\n";
    let scan = parse_and_extract_orchestration(ts, "echo_return_call.ts").expect("ts scans");
    assert!(
        !supports_gg_embed_for_export(&scan, "app"),
        "return-position helper calls are outside the walker subset (typescript)"
    );

    let rb = "def greet(name)\n  \"hello:#{name}\"\nend\n\ndef app(input)\n  message = greet(input[\"name\"])\n  return message\nend\n";
    let scan = parse_and_extract_orchestration(rb, "echo_implicit.rb").expect("rb scans");
    assert!(
        !supports_gg_embed_for_export(&scan, "app"),
        "ruby implicit returns carry no expr IR; the program must decline"
    );
}
